import React from "react";
import { NavLink } from "react-router-dom";

export default function AdminNavBar() {
  const role = localStorage.getItem("role");

  // 🚫 Only Admin & Academic Panel
  if (role !== "Admin" && role !== "Academic Panel") {
    return null;
  }

  return (
    <div className="fixed top-0 left-0 h-full w-64 bg-gray-900 text-white pt-20 p-6">

      <h2 className="text-xl font-bold mb-6">
        {role === "Admin" ? "Admin Panel" : "Academic Panel"}
      </h2>

      <ul className="space-y-4">

        {/* ADMIN MENU */}
        {role === "Admin" && (
          <>
            <li><NavLink to="/admin/users">Users</NavLink></li>
            <li><NavLink to="/admin/reports">Reports</NavLink></li>
            <li><NavLink to="/admin/settings">Settings</NavLink></li>
            <li><NavLink to="/admin/add-user">Add User</NavLink></li>
          </>
        )}

        {/* ACADEMIC PANEL MENU */}
        {role === "Academic Panel" && (
          <>
            <li><NavLink to="/resources">My Resources</NavLink></li>
            <li><NavLink to="/tasks">Tasks</NavLink></li>
            <li><NavLink to="/students">Students</NavLink></li>
          </>
        )}

      </ul>
    </div>
  );
}
